# Pester tests for DependencyLicenseChecker
# TDD approach: each Describe block represents a feature built test-first

BeforeAll {
    . $PSScriptRoot/DependencyLicenseChecker.Functions.ps1
}

Describe "Parse-PackageJson" {
    It "parses production dependencies from package.json" {
        $result = Parse-PackageJson -Path "$PSScriptRoot/fixtures/package.json"
        $prodDeps = $result | Where-Object { $_.Type -eq "production" }
        $prodDeps.Count | Should -Be 3
    }

    It "extracts dependency names correctly" {
        $result = Parse-PackageJson -Path "$PSScriptRoot/fixtures/package.json"
        $names = $result | ForEach-Object { $_.Name }
        $names | Should -Contain "express"
        $names | Should -Contain "lodash"
        $names | Should -Contain "axios"
    }

    It "parses devDependencies" {
        $result = Parse-PackageJson -Path "$PSScriptRoot/fixtures/package.json"
        $devDeps = $result | Where-Object { $_.Type -eq "development" }
        $devDeps.Count | Should -Be 1
        $devDeps[0].Name | Should -Be "jest"
    }

    It "strips version prefixes" {
        $result = Parse-PackageJson -Path "$PSScriptRoot/fixtures/package.json"
        $express = $result | Where-Object { $_.Name -eq "express" }
        $express.Version | Should -Be "4.18.2"
    }

    It "throws on missing file" {
        { Parse-PackageJson -Path "/nonexistent/package.json" } | Should -Throw "*not found*"
    }
}

Describe "Parse-RequirementsTxt" {
    It "parses pinned dependencies" {
        $result = Parse-RequirementsTxt -Path "$PSScriptRoot/fixtures/requirements.txt"
        $result.Count | Should -Be 4
    }

    It "extracts names and versions correctly" {
        $result = Parse-RequirementsTxt -Path "$PSScriptRoot/fixtures/requirements.txt"
        $flask = $result | Where-Object { $_.Name -eq "flask" }
        $flask.Version | Should -Be "3.0.0"
    }

    It "handles hyphenated package names" {
        $result = Parse-RequirementsTxt -Path "$PSScriptRoot/fixtures/requirements.txt"
        $gpl = $result | Where-Object { $_.Name -eq "gpl-library" }
        $gpl | Should -Not -BeNullOrEmpty
        $gpl.Version | Should -Be "1.0.0"
    }

    It "throws on missing file" {
        { Parse-RequirementsTxt -Path "/nonexistent/requirements.txt" } | Should -Throw "*not found*"
    }
}

Describe "Read-LicenseConfig" {
    It "loads allowed and denied license lists" {
        $config = Read-LicenseConfig -Path "$PSScriptRoot/fixtures/license-config.json"
        $config.AllowedLicenses | Should -Contain "MIT"
        $config.DeniedLicenses | Should -Contain "GPL-3.0"
    }

    It "loads the license database" {
        $config = Read-LicenseConfig -Path "$PSScriptRoot/fixtures/license-config.json"
        $config.LicenseDatabase["express"] | Should -Be "MIT"
        $config.LicenseDatabase["gpl-library"] | Should -Be "GPL-3.0"
    }

    It "throws on missing config" {
        { Read-LicenseConfig -Path "/nonexistent/config.json" } | Should -Throw "*not found*"
    }
}

Describe "Get-LicenseForDependency" {
    It "returns the license from the database" {
        $db = @{ "express" = "MIT"; "numpy" = "BSD-3-Clause" }
        Get-LicenseForDependency -DependencyName "express" -LicenseDatabase $db | Should -Be "MIT"
    }

    It "returns null for unknown dependencies" {
        $db = @{ "express" = "MIT" }
        Get-LicenseForDependency -DependencyName "unknown-pkg" -LicenseDatabase $db | Should -BeNullOrEmpty
    }
}

Describe "Get-LicenseStatus" {
    It "returns approved for allowed licenses" {
        $result = Get-LicenseStatus -License "MIT" -AllowedLicenses @("MIT", "Apache-2.0") -DeniedLicenses @("GPL-3.0")
        $result | Should -Be "approved"
    }

    It "returns denied for denied licenses" {
        $result = Get-LicenseStatus -License "GPL-3.0" -AllowedLicenses @("MIT") -DeniedLicenses @("GPL-3.0", "AGPL-3.0")
        $result | Should -Be "denied"
    }

    It "returns unknown for unrecognized licenses" {
        $result = Get-LicenseStatus -License "Artistic-2.0" -AllowedLicenses @("MIT") -DeniedLicenses @("GPL-3.0")
        $result | Should -Be "unknown"
    }

    It "returns unknown for null license" {
        $result = Get-LicenseStatus -License $null -AllowedLicenses @("MIT") -DeniedLicenses @("GPL-3.0")
        $result | Should -Be "unknown"
    }
}

Describe "Invoke-LicenseCheck" {
    It "checks package.json dependencies against config" {
        $results = Invoke-LicenseCheck -ManifestPath "$PSScriptRoot/fixtures/package.json" -ConfigPath "$PSScriptRoot/fixtures/license-config.json"
        $results.Count | Should -Be 4
    }

    It "correctly identifies approved dependencies" {
        $results = Invoke-LicenseCheck -ManifestPath "$PSScriptRoot/fixtures/package.json" -ConfigPath "$PSScriptRoot/fixtures/license-config.json"
        $approved = @($results | Where-Object { $_.Status -eq "approved" })
        $approved.Count | Should -Be 4
    }

    It "correctly identifies denied dependencies in requirements.txt" {
        $results = Invoke-LicenseCheck -ManifestPath "$PSScriptRoot/fixtures/requirements.txt" -ConfigPath "$PSScriptRoot/fixtures/license-config.json"
        $denied = @($results | Where-Object { $_.Status -eq "denied" })
        $denied.Count | Should -Be 1
        $denied[0].Name | Should -Be "gpl-library"
    }

    It "throws on unsupported manifest format" {
        # Create a temp file with unsupported name
        $tempFile = Join-Path $TestDrive "Gemfile"
        Set-Content -Path $tempFile -Value "gem 'rails'"
        { Invoke-LicenseCheck -ManifestPath $tempFile -ConfigPath "$PSScriptRoot/fixtures/license-config.json" } | Should -Throw "*Unsupported*"
    }
}

Describe "Format-ComplianceReport" {
    It "generates a report with correct counts" {
        $results = @(
            @{ Name = "express"; Version = "4.18.2"; Type = "production"; License = "MIT"; Status = "approved" },
            @{ Name = "gpl-lib"; Version = "1.0.0"; Type = "production"; License = "GPL-3.0"; Status = "denied" }
        )
        $report = Format-ComplianceReport -Results $results -ManifestPath "package.json"
        $report | Should -Match "Total dependencies: 2"
        $report | Should -Match "Approved: 1"
        $report | Should -Match "Denied: 1"
    }

    It "shows FAIL when denied dependencies exist" {
        $results = @(
            @{ Name = "gpl-lib"; Version = "1.0.0"; Type = "production"; License = "GPL-3.0"; Status = "denied" }
        )
        $report = Format-ComplianceReport -Results $results -ManifestPath "test.json"
        $report | Should -Match "RESULT: FAIL"
    }

    It "shows PASS when all approved" {
        $results = @(
            @{ Name = "express"; Version = "4.18.2"; Type = "production"; License = "MIT"; Status = "approved" }
        )
        $report = Format-ComplianceReport -Results $results -ManifestPath "test.json"
        $report | Should -Match "RESULT: PASS"
    }

    It "shows WARN when unknown licenses present but no denied" {
        $results = @(
            @{ Name = "mystery"; Version = "1.0.0"; Type = "production"; License = "UNKNOWN"; Status = "unknown" }
        )
        $report = Format-ComplianceReport -Results $results -ManifestPath "test.json"
        $report | Should -Match "RESULT: WARN"
    }

    It "includes dependency details with status tags" {
        $results = @(
            @{ Name = "express"; Version = "4.18.2"; Type = "production"; License = "MIT"; Status = "approved" }
        )
        $report = Format-ComplianceReport -Results $results -ManifestPath "test.json"
        $report | Should -Match "\[APPROVED\] express@4.18.2"
    }
}

Describe "End-to-end integration" {
    It "produces complete report for package.json with all approved" {
        $results = Invoke-LicenseCheck -ManifestPath "$PSScriptRoot/fixtures/package.json" -ConfigPath "$PSScriptRoot/fixtures/license-config.json"
        $report = Format-ComplianceReport -Results $results -ManifestPath "$PSScriptRoot/fixtures/package.json"
        $report | Should -Match "RESULT: PASS"
        $report | Should -Match "\[APPROVED\] express@4.18.2"
        $report | Should -Match "\[APPROVED\] lodash@4.17.21"
    }

    It "produces complete report for requirements.txt with denied deps" {
        $results = Invoke-LicenseCheck -ManifestPath "$PSScriptRoot/fixtures/requirements.txt" -ConfigPath "$PSScriptRoot/fixtures/license-config.json"
        $report = Format-ComplianceReport -Results $results -ManifestPath "$PSScriptRoot/fixtures/requirements.txt"
        $report | Should -Match "RESULT: FAIL"
        $report | Should -Match "\[DENIED\] gpl-library@1.0.0"
        $report | Should -Match "\[APPROVED\] flask@3.0.0"
    }
}

# Test harness that runs all tests through GitHub Actions via act
# Creates temp git repos with fixtures, runs act, captures output, asserts results

$ErrorActionPreference = "Stop"
$ProjectRoot = $PSScriptRoot
$ActResultFile = Join-Path $ProjectRoot "act-result.txt"

# Clear previous results
if (Test-Path $ActResultFile) { Remove-Item $ActResultFile }
"" | Set-Content $ActResultFile

$allPassed = $true

function Run-ActTest {
    param(
        [string]$TestName,
        [string]$Description
    )

    Write-Host "`n========================================" -ForegroundColor Cyan
    Write-Host "TEST: $TestName" -ForegroundColor Cyan
    Write-Host "$Description" -ForegroundColor Cyan
    Write-Host "========================================" -ForegroundColor Cyan

    # Create temp directory for isolated git repo
    $tempDir = Join-Path ([System.IO.Path]::GetTempPath()) "act-test-$(Get-Random)"
    New-Item -ItemType Directory -Path $tempDir -Force | Out-Null

    try {
        # Copy project files
        Copy-Item "$ProjectRoot/DependencyLicenseChecker.ps1" $tempDir/
        Copy-Item "$ProjectRoot/DependencyLicenseChecker.Functions.ps1" $tempDir/
        Copy-Item "$ProjectRoot/DependencyLicenseChecker.Tests.ps1" $tempDir/
        Copy-Item -Recurse "$ProjectRoot/fixtures" "$tempDir/fixtures"
        Copy-Item -Recurse "$ProjectRoot/.github" "$tempDir/.github"
        Copy-Item "$ProjectRoot/.actrc" "$tempDir/.actrc"

        # Initialize git repo (act requires it)
        Push-Location $tempDir
        git init --quiet
        git add -A
        git commit -m "test setup" --quiet

        # Run act
        $actOutput = & act push --rm 2>&1 | Out-String
        $actExitCode = $LASTEXITCODE

        Pop-Location

        # Append to results file
        $delimiter = "`n`n" + ("=" * 60) + "`n"
        $entry = "${delimiter}TEST CASE: $TestName`n$Description`nExit Code: $actExitCode`n" + ("=" * 60) + "`n$actOutput"
        Add-Content -Path $ActResultFile -Value $entry

        return @{
            Output   = $actOutput
            ExitCode = $actExitCode
        }
    }
    finally {
        if (Test-Path $tempDir) {
            Remove-Item -Recurse -Force $tempDir
        }
    }
}

# ============================================================
# WORKFLOW STRUCTURE TESTS (YAML parsing, actionlint, file refs)
# ============================================================

Write-Host "`n" -NoNewline
Write-Host "=== WORKFLOW STRUCTURE TESTS ===" -ForegroundColor Yellow

# Test 1: actionlint passes
Write-Host "`nStructure Test 1: actionlint validation..." -ForegroundColor White
$lintResult = & actionlint "$ProjectRoot/.github/workflows/dependency-license-checker.yml" 2>&1
$lintExit = $LASTEXITCODE
if ($lintExit -eq 0) {
    Write-Host "  PASS: actionlint passes with exit code 0" -ForegroundColor Green
} else {
    Write-Host "  FAIL: actionlint exit code $lintExit" -ForegroundColor Red
    Write-Host "  $lintResult" -ForegroundColor Red
    $allPassed = $false
}
Add-Content -Path $ActResultFile -Value "`n=== STRUCTURE TEST: actionlint ===`nExit code: $lintExit`n$lintResult"

# Test 2: YAML structure validation
Write-Host "`nStructure Test 2: YAML structure..." -ForegroundColor White
$yaml = Get-Content "$ProjectRoot/.github/workflows/dependency-license-checker.yml" -Raw

$hasOnPush = $yaml -match "on:" -and $yaml -match "push:"
$hasJobs = $yaml -match "jobs:"
$hasTest = $yaml -match "test:"
$hasCheckout = $yaml -match "actions/checkout@v4"
$hasPwsh = $yaml -match "shell: pwsh"

if ($hasOnPush -and $hasJobs -and $hasTest -and $hasCheckout -and $hasPwsh) {
    Write-Host "  PASS: Workflow has correct structure (triggers, jobs, checkout, pwsh)" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Missing workflow elements" -ForegroundColor Red
    $allPassed = $false
}
Add-Content -Path $ActResultFile -Value "`n=== STRUCTURE TEST: YAML structure ===`non.push: $hasOnPush | jobs: $hasJobs | test: $hasTest | checkout: $hasCheckout | pwsh: $hasPwsh"

# Test 3: Script files referenced in workflow exist
Write-Host "`nStructure Test 3: Script file references..." -ForegroundColor White
$scriptsExist = (Test-Path "$ProjectRoot/DependencyLicenseChecker.ps1") -and
                (Test-Path "$ProjectRoot/DependencyLicenseChecker.Functions.ps1") -and
                (Test-Path "$ProjectRoot/DependencyLicenseChecker.Tests.ps1") -and
                (Test-Path "$ProjectRoot/fixtures/package.json") -and
                (Test-Path "$ProjectRoot/fixtures/requirements.txt") -and
                (Test-Path "$ProjectRoot/fixtures/license-config.json")
if ($scriptsExist) {
    Write-Host "  PASS: All referenced script and fixture files exist" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Some referenced files are missing" -ForegroundColor Red
    $allPassed = $false
}
Add-Content -Path $ActResultFile -Value "`n=== STRUCTURE TEST: File references ===`nAll files exist: $scriptsExist"

# ============================================================
# ACT INTEGRATION TEST
# ============================================================

Write-Host "`n`n=== ACT INTEGRATION TEST ===" -ForegroundColor Yellow

$result = Run-ActTest -TestName "Full Pipeline" -Description "Run complete workflow: unit tests + package.json check + requirements.txt denied detection"

# Assert act exited successfully
if ($result.ExitCode -eq 0) {
    Write-Host "  PASS: act exited with code 0" -ForegroundColor Green
} else {
    Write-Host "  FAIL: act exited with code $($result.ExitCode)" -ForegroundColor Red
    Write-Host "  Output (last 50 lines):" -ForegroundColor Red
    $lines = $result.Output -split "`n"
    $lines[-50..-1] | ForEach-Object { Write-Host "    $_" -ForegroundColor Red }
    $allPassed = $false
}

# Assert all jobs succeeded
$jobSucceeded = ($result.Output -match "Job succeeded")
if ($jobSucceeded) {
    Write-Host "  PASS: Jobs reported success" -ForegroundColor Green
} else {
    Write-Host "  FAIL: No 'Job succeeded' found in output" -ForegroundColor Red
    $allPassed = $false
}

# Assert Pester tests ran and passed
$pesterPassed = ($result.Output -match "Tests Passed")
if ($pesterPassed) {
    Write-Host "  PASS: Pester tests passed" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Pester test results not found" -ForegroundColor Red
    $allPassed = $false
}

# Assert package.json check shows RESULT: PASS (all MIT deps)
$passResult = ($result.Output -match "RESULT: PASS")
if ($passResult) {
    Write-Host "  PASS: package.json check shows 'RESULT: PASS'" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Expected 'RESULT: PASS' for package.json" -ForegroundColor Red
    $allPassed = $false
}

# Assert requirements.txt check correctly detected denied licenses
$deniedDetected = ($result.Output -match "Correctly detected denied licenses")
if ($deniedDetected) {
    Write-Host "  PASS: requirements.txt denied license detection confirmed" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Expected denied license detection message" -ForegroundColor Red
    $allPassed = $false
}

# Assert specific dependency details in output
$expressApproved = ($result.Output -match "\[APPROVED\] express@4.18.2")
if ($expressApproved) {
    Write-Host "  PASS: express@4.18.2 correctly shown as [APPROVED]" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Expected '[APPROVED] express@4.18.2' in output" -ForegroundColor Red
    $allPassed = $false
}

$gplDenied = ($result.Output -match "\[DENIED\] gpl-library@1.0.0")
if ($gplDenied) {
    Write-Host "  PASS: gpl-library@1.0.0 correctly shown as [DENIED]" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Expected '[DENIED] gpl-library@1.0.0' in output" -ForegroundColor Red
    $allPassed = $false
}

# Assert correct counts in package.json report
$totalDeps4 = ($result.Output -match "Total dependencies: 4")
if ($totalDeps4) {
    Write-Host "  PASS: package.json reports exactly 4 total dependencies" -ForegroundColor Green
} else {
    Write-Host "  FAIL: Expected 'Total dependencies: 4' for package.json" -ForegroundColor Red
    $allPassed = $false
}

# ============================================================
# FINAL SUMMARY
# ============================================================

Write-Host "`n`n========================================" -ForegroundColor Cyan
if ($allPassed) {
    Write-Host "ALL TESTS PASSED" -ForegroundColor Green
} else {
    Write-Host "SOME TESTS FAILED" -ForegroundColor Red
    exit 1
}
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Results saved to: $ActResultFile"
